<script setup lang="ts">import{onMounted,reactive,ref,watch}from'vue';import{useRoute,useRouter}from'vue-router';import PageState from'../components/feedback/PageState.vue';import CheckinDetailDrawer from'../features/records/CheckinDetailDrawer.vue';import{listCheckins}from'../services/management/records';import{useSceneStore}from'../stores/scene';import type{CheckinRecord}from'../types/records';const route=useRoute(),router=useRouter(),scene=useSceneStore(),items=ref<CheckinRecord[]>([]),loading=ref(true),error=ref(''),selected=ref<CheckinRecord|null>(null);const f=reactive({status:String(route.query.status||''),spotId:String(route.query.spot_id||''),deviceId:String(route.query.device_id||''),cardId:String(route.query.card_id||''),userId:String(route.query.user_id||''),dateFrom:String(route.query.date_from||''),dateTo:String(route.query.date_to||'')});async function load(){loading.value=true;error.value='';try{await router.replace({query:Object.fromEntries(Object.entries({status:f.status,spot_id:f.spotId,device_id:f.deviceId,card_id:f.cardId,user_id:f.userId,date_from:f.dateFrom,date_to:f.dateTo}).filter(([,v])=>v))});items.value=(await listCheckins({sceneId:scene.currentSceneId,...f,pageSize:100})).data.items}catch(e){error.value=e instanceof Error?e.message:'打卡事件加载失败'}finally{loading.value=false}}onMounted(load);watch(()=>scene.currentSceneId,load);const label=(s:string)=>s==='accepted'?'✓ 已接受':s==='duplicate'?'↺ 重复':`! ${s}`</script>
<template><div class="page"><header><p>DATA TRACE</p><h1>打卡事件</h1><span>跨点位、设备、卡片和用户定位原始事件</span></header><section class="filters wrap"><select v-model="f.status"><option value="">全部状态</option><option value="accepted">已接受</option><option value="rejected">已拒绝</option><option value="duplicate">重复</option></select><input v-model.trim="f.spotId" placeholder="点位 ID"/><input v-model.trim="f.deviceId" placeholder="设备 ID"/><input v-model.trim="f.cardId" placeholder="卡片 ID"/><input v-model.trim="f.userId" placeholder="用户 ID"/><input v-model="f.dateFrom" type="date"/><input v-model="f.dateTo" type="date"/><button @click="load">查询并生成链接</button></section><PageState v-if="loading&&items.length===0" status="loading"/><PageState v-else-if="error" status="error" :description="error" @retry="load"/><PageState v-else-if="items.length===0" status="empty" title="暂无打卡事件"/><section v-else class="table"><table><thead><tr><th>时间</th><th>事件</th><th>方式</th><th>状态</th><th>失败码</th><th>操作</th></tr></thead><tbody><tr v-for="e in items" :key="e.id"><td>{{e.received_at}}</td><td>{{e.event_id}}</td><td>{{e.checkin_type.toUpperCase()}}</td><td>{{label(e.status)}}</td><td>{{e.failure_code||'—'}}</td><td><button @click="selected=e">详情</button></td></tr></tbody></table></section><CheckinDetailDrawer :model-value="Boolean(selected)" :event="selected" @update:model-value="!$event&&(selected=null)"/></div></template>
<style scoped>@import '../styles/records-page.css';</style>
